### तर्क

1. **दोनों एरेज़ की तुलना करें**: हम दोनों एरेज़ के एलिमेंट्स की तुलना कर सकते हैं और जहां अंतर हो, वहां अतिरिक्त एलिमेंट का इंडेक्स ढूंढ सकते हैं।

2. **बाइनरी सर्च**: हम बाइनरी सर्च एल्गोरिथम का उपयोग करके भी अतिरिक्त एलिमेंट का इंडेक्स ढूंढ सकते हैं।

### पाइथन फंक्शन

```python
def find_Extra(arr1, arr2):
    # दोनों एरेज़ को मर्ज करें और सॉर्ट करें
    merged = sorted(arr1 + arr2)

    # डुप्लिकेट एलिमेंट ढूंढें
    for i in range(len(merged) - 1):
        if merged[i] == merged[i + 1]:
            return merged.index(merged[i])
    return -1

# या फिर

def find_Extra(arr1, arr2):
    # बाइनरी सर्च
    def binary_search(arr, target):
        low, high = 0, len(arr) - 1
        while low <= high:
            mid = (low + high) // 2
            if arr[mid] == target:
                return mid
            elif arr[mid] < target:
                low = mid + 1
            else:
                high = mid - 1
        return -1

    for num in arr1:
        index = binary_search(arr2, num)
        if index == -1:
            return arr1.index(num)
    return arr2.index(arr1[0])

# उदाहरण के लिए

arr1 = [1, 2, 3, 4, 5, 6]
arr2 = [1, 2, 3, 4, 5]

print(find_Extra(arr1, arr2))  # आउटपुट: 5
```

इस फंक्शन में, हमने दो तरीके अपनाए हैं: एक मर्ज और सॉर्ट करके, और दूसरा बाइनरी सर्च का उपयोग करके। दोनों तरीकों में, हम अतिरिक्त एलिमेंट का इंडेक्स ढूंढते हैं। यदि आपको और स्पष्टीकरण चाहिए, तो कृपया पूछें।

```python
public class Program
{
    static int min intArray(int[,] cost, int m, int n)
    {
        //cost.Intialization 
        int[,] dp = new int[m+1,n+1];
        //Base Case har ka Intial point  cost 0,0 he 

        dp[0,0] =cost[0,0]; 

        //cost DP First Column Calculation 
        for(int i =1;i<m;++i++)
        {
            dp[i,0]= dp[i,0]+cost[i,0]; 
        }

        //DP  DP First Row Calculation Row Calculation 
        for(int j=1;j<n;++j++)
        {
            dp[0,j]= dp[0,j]+cost[0,j]; 
        }

        //DP Dynamic Programming Iteration Matrix Fill Up Har Steps
        for(int i=1;i<m;++i++)
        {
            for(int j= 1;j<n;++j++)
            {

                dp[i,j= Math.Min(dp[i-1,j]+cost[i,j],dp[i,j-1] + cost[i,j]);

            }

        }

        return dp[m,n]; 
    }

}
